impl<'a> syntaqlite_parser::ast_traits::SelectLike<'a> for Select<'a> {
    type Ast = SqliteAst;
    fn kind(&self) -> syntaqlite_parser::ast_traits::SelectKind<'a, SqliteAst> {
        match *self {
            Select::SelectStmt(n) => syntaqlite_parser::ast_traits::SelectKind::SelectStmt(n),
            Select::CompoundSelect(n) => {
                syntaqlite_parser::ast_traits::SelectKind::CompoundSelect(n)
            }
            Select::WithClause(n) => syntaqlite_parser::ast_traits::SelectKind::WithClause(n),
            Select::ValuesClause(n) => syntaqlite_parser::ast_traits::SelectKind::ValuesClause(n),
            Select::Other(n) => syntaqlite_parser::ast_traits::SelectKind::Other(n),
        }
    }
}

